-- ============================================================
-- 17. TICKET_COMMENTS (35 rows)
-- ============================================================

INSERT INTO smartstay.ticket_comments (id, ticket_id, author_id, content, is_internal, created_at) VALUES
  -- Ticket 1 (AC not cooling)
  (1,  1, 'a1b2c3d4-1111-4000-a000-000000000002', 'Đã kiểm tra, máy thiếu gas và dàn lạnh bẩn. Lên lịch bảo trì ngày mai.', false, '2025-11-11T10:00:00+07:00'),
  (2,  1, 'a1b2c3d4-1111-4000-a000-000000000002', 'Đã nạp gas R32 và vệ sinh dàn lạnh. Máy hoạt động bình thường.', false, '2025-11-15T15:00:00+07:00'),
  (3,  1, '090a09fc-523f-4a72-8506-fbb76300bf0f', 'Cảm ơn, máy lạnh đã mát trở lại.', false, '2025-11-15T18:00:00+07:00'),
  -- Ticket 2 (Water leak)
  (4,  2, 'a1b2c3d4-1111-4000-a000-000000000002', 'Tình huống khẩn cấp, đã cử thợ đến ngay.', false, '2025-11-20T08:00:00+07:00'),
  (5,  2, 'a1b2c3d4-1111-4000-a000-000000000002', 'Đã tắt van nước tổng và thay ống. Xong trước 10h.', false, '2025-11-21T09:30:00+07:00'),
  (6,  2, 'a1b2c3d4-2222-4000-a000-000000000003', 'Xử lý rất nhanh, cảm ơn ban quản lý!', false, '2025-11-21T11:00:00+07:00'),
  -- Ticket 3 (TV broken)
  (7,  3, 'a1b2c3d4-1111-4000-a000-000000000001', 'Đã liên hệ bảo hành Samsung, hẹn kiểm tra thứ 4.', false, '2025-12-02T10:00:00+07:00'),
  (8,  3, 'a1b2c3d4-1111-4000-a000-000000000001', 'Samsung xác nhận lỗi nguồn, thay nguồn mới miễn phí (còn bảo hành).', false, '2025-12-05T13:00:00+07:00'),
  -- Ticket 4 (Wifi weak)
  (9,  4, 'a1b2c3d4-1111-4000-a000-000000000001', 'Đã kiểm tra cường độ tín hiệu, tầng 2 có vùng chết. Đề xuất lắp repeater.', true, '2025-12-11T09:00:00+07:00'),
  (10, 4, 'a1b2c3d4-1111-4000-a000-000000000001', 'Đã lắp TP-Link RE605X tại hành lang tầng 2. Tín hiệu cải thiện rõ rệt.', false, '2025-12-12T10:00:00+07:00'),
  (11, 4, 'a1b2c3d4-2222-4000-a000-000000000004', 'Wifi đã ổn định hơn nhiều, cảm ơn!', false, '2025-12-12T15:00:00+07:00'),
  -- Ticket 5 (Noise)
  (12, 5, 'a1b2c3d4-1111-4000-a000-000000000001', 'Đã gửi thông báo nhắc nhở tới cư dân phòng B-202.', false, '2025-12-16T10:00:00+07:00'),
  (13, 5, '090a09fc-523f-4a72-8506-fbb76300bf0f', 'Tối qua vẫn còn ồn nhưng đỡ hơn trước.', false, '2025-12-18T08:00:00+07:00'),
  (14, 5, 'a1b2c3d4-1111-4000-a000-000000000001', 'Đã gọi điện trực tiếp cho cư dân, họ cam kết sẽ giảm tiếng ồn.', false, '2025-12-19T10:00:00+07:00'),
  -- Ticket 6 (AC dripping)
  (15, 6, 'a1b2c3d4-1111-4000-a000-000000000002', 'Có thể do tắc ống thoát nước, sẽ kiểm tra chiều nay.', false, '2026-01-15T14:00:00+07:00'),
  (16, 6, 'a1b2c3d4-1111-4000-a000-000000000002', 'Nội bộ: cần đặt bộ bơm xả nước mới, hàng về trong 2 ngày.', true, '2026-01-16T09:00:00+07:00'),
  -- Ticket 7 (Window gap)
  (17, 7, 'a1b2c3d4-1111-4000-a000-000000000002', 'Đã chỉnh bản lề và thay gioăng. Xin xác nhận đã khắc phục.', false, '2026-01-25T14:00:00+07:00'),
  -- Ticket 9 (Water heater)
  (18, 9, 'a1b2c3d4-1111-4000-a000-000000000002', 'Đã cử thợ kiểm tra ngay, xác định hỏng thanh đốt.', false, '2026-02-01T10:00:00+07:00'),
  (19, 9, 'a1b2c3d4-1111-4000-a000-000000000002', 'Đã thay thanh đốt Ariston chính hãng, bình nóng lạnh hoạt động bình thường.', false, '2026-02-03T15:00:00+07:00'),
  (20, 9, 'a1b2c3d4-2222-4000-a000-000000000004', 'Nước nóng lại rồi, cảm ơn sửa nhanh!', false, '2026-02-03T18:00:00+07:00'),
  -- Ticket 10 (Elevator stuck)
  (21, 10, 'a1b2c3d4-1111-4000-a000-000000000001', 'Đã liên hệ đơn vị bảo trì thang máy Mitsubishi. Hẹn kiểm tra thứ 6.', false, '2026-02-11T10:00:00+07:00'),
  (22, 10, 'a1b2c3d4-1111-4000-a000-000000000001', 'Nội bộ: báo giá thay ray dẫn hướng 15 triệu. Chờ duyệt BGĐ.', true, '2026-02-12T10:00:00+07:00'),
  -- Ticket 11 (Hallway light)
  (23, 11, 'a1b2c3d4-1111-4000-a000-000000000002', 'Đã thay bóng LED Philips 18W, hành lang sáng trở lại.', false, '2026-02-18T09:00:00+07:00'),
  -- Ticket 14 (Water smell)
  (24, 14, 'a1b2c3d4-1111-4000-a000-000000000002', 'Đã lấy mẫu nước gửi kiểm nghiệm. Kết quả trong 2 ngày.', false, '2026-03-10T14:00:00+07:00'),
  (25, 14, 'a1b2c3d4-1111-4000-a000-000000000002', 'Nội bộ: có thể do bể chứa chưa được vệ sinh quý này.', true, '2026-03-11T09:00:00+07:00'),
  -- Ticket 16 (Loose socket)
  (26, 16, 'a1b2c3d4-1111-4000-a000-000000000002', 'CẢNH BÁO: Không sử dụng ổ cắm này cho đến khi sửa xong. Đã cử thợ điện.', false, '2026-03-15T08:00:00+07:00'),
  (27, 16, 'a1b2c3d4-1111-4000-a000-000000000002', 'Nội bộ: ổ cắm lỏng do thi công ban đầu, cần kiểm tra tất cả ổ cắm tầng 3.', true, '2026-03-15T09:00:00+07:00'),
  -- Ticket 19 (Parking)
  (28, 19, 'a1b2c3d4-1111-4000-a000-000000000001', 'Đã họp với bộ phận an ninh, sẽ bổ sung thêm chỗ gửi xe.', false, '2026-01-16T10:00:00+07:00'),
  (29, 19, 'a1b2c3d4-1111-4000-a000-000000000001', 'Đã mở thêm 10 chỗ gửi xe máy tại tầng hầm B2.', false, '2026-01-20T09:00:00+07:00'),
  (30, 19, '090a09fc-523f-4a72-8506-fbb76300bf0f', 'Tốt rồi, giờ luôn có chỗ gửi xe.', false, '2026-01-21T08:00:00+07:00'),
  -- Ticket 20 (AC maintenance)
  (31, 20, 'a1b2c3d4-1111-4000-a000-000000000002', 'Đã lên lịch bảo trì chiều nay 14h-15h.', false, '2026-03-22T10:00:00+07:00'),
  (32, 20, 'a1b2c3d4-1111-4000-a000-000000000002', 'Đã vệ sinh dàn lạnh, kiểm tra gas đầy đủ. Xin xác nhận hoàn thành.', false, '2026-03-23T10:00:00+07:00'),
  -- Extra comments for diversity
  (33, 8, 'a1b2c3d4-1111-4000-a000-000000000001', 'Đã giao thẻ từ mới cho cư dân. Phí 50.000đ sẽ cộng vào hóa đơn tháng sau.', false, '2026-01-10T10:00:00+07:00'),
  (34, 12, 'a1b2c3d4-1111-4000-a000-000000000002', 'Nội bộ: cần kiểm tra compressor, có thể phải thay mới nếu hỏng.', true, '2026-03-02T10:00:00+07:00'),
  (35, 13, 'a1b2c3d4-1111-4000-a000-000000000001', 'Hiện tại phòng B-202 (3BR) đang bảo trì. Sẽ liên hệ khi sẵn sàng.', false, '2026-03-06T10:00:00+07:00');

